import java.util.*;

class Solution {
    public List<Integer> findSubstring(String s, String[] words) {
        List<Integer> result = new ArrayList<>();
        if (s == null || s.length() == 0 || words == null || words.length == 0) {
            return result;
        }

        int wordCount = words.length;
        int wordLength = words[0].length();
        Map<String, Integer> wordMap = new HashMap<>();

        for (String word : words) {
            wordMap.put(word, wordMap.getOrDefault(word, 0) + 1);
        }

        for (int i = 0; i <= s.length() - wordCount * wordLength; i++) {
            Map<String, Integer> tempMap = new HashMap<>(wordMap);
            for (int j = 0; j < wordCount; j++) {
                int start = i + j * wordLength;
                String temp = s.substring(start, start + wordLength);
                if (!tempMap.containsKey(temp) || tempMap.get(temp) <= 0) {
                    break;
                }
                tempMap.put(temp, tempMap.get(temp) - 1);
                if (j == wordCount - 1) {
                    result.add(i);
                }
            }
        }
        return result;
    }
}
